    // Section 4 — Import
    'features.s4.label':          'Розділ четвертий',
    'features.s4.h2':             '<em>Імпорт</em>.',
    'features.s4.intro':          'Як додавати книги, які формати підтримуються і які важелі у вас є, коли нова книга потрапляє до бібліотеки.',

    'features.s4.formats.h':      'Підтримувані формати',
